const startedAt = new Date().toISOString();
const logId = $input.first().json[0]?.id || $input.first().json?.id;
return [{ json: { log_id: logId, started_at: startedAt } }];

const prev = $('Extract Log ID').first().json;
const stdout = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode;

// Try to parse rows_upserted from stdout
let rowsUpserted = 0;
const match = stdout.match(/rows_upserted["']?\s*[:=]\s*(\d+)/);
if (match) {
  rowsUpserted = parseInt(match[1], 10);
}

// Also try JSON parsing
try {
  const lines = stdout.trim().split('\n');
  for (const line of lines) {
    if (line.includes('{')) {
      const parsed = JSON.parse(line.substring(line.indexOf('{')));
      if (parsed.rows_upserted !== undefined) {
        rowsUpserted = parsed.rows_upserted;
      }
    }
  }
} catch(e) {}

const startedAt = new Date(prev.started_at);
const durationSec = Math.round((Date.now() - startedAt.getTime()) / 1000);

if (exitCode !== 0) {
  throw new Error(`ETL script failed (exit ${exitCode}): ${stdout.substring(0, 500)}`);
}

return [{ json: {
  log_id: prev.log_id,
  rows_upserted: rowsUpserted,
  duration_sec: durationSec,
  stdout: stdout
}}];

const errorMsg = $input.first().json.execution?.error?.message || 'Unknown error';
// Try to get log_id from execution data
let logId = null;
try {
  const execData = $input.first().json.execution?.data?.resultData?.runData;
  if (execData && execData['Extract Log ID']) {
    logId = execData['Extract Log ID'][0]?.data?.main?.[0]?.[0]?.json?.log_id;
  }
} catch(e) {}

return [{ json: { log_id: logId, error_message: errorMsg.substring(0, 1000) } }];
